import React from 'react';

function About() {
    return ( <>
            <main className="container">
                <h1 className='text-center mt-5 mb-5 border-bottom'>About Me</h1>
                <p>I have done my Bachelor’s degree in Computer Science (BCS) from Savitribai Phule Pune University and a Full Stack Web Development (MERN Stack) certification. I have hands-on experience building responsive and scalable web applications.

My technical skills include React.js, Node.js, Express.js, MongoDB, Git, and GitHub, with a focus on frontend development, backend development, REST APIs, and database management.

Currently working in Digital Marketing at SSIC – Your Packaging Partner, I bring strong communication, analytical, and teamwork skills that support my technical role.

I am actively seeking entry-level / fresher opportunities as a MERN Stack Developer or Junior Web Developer to grow and contribute to real-world projects.</p>
            </main>
    </> );
}

export default About;
